<?php include 'header.php'; $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $name=trim($_POST['name']); $email=trim($_POST['email']); $password=$_POST['password']; if(strlen($password)<6){$error='Password must be at least 6 characters.';} else {try{$hash=password_hash($password,PASSWORD_DEFAULT); $stmt=$pdo->prepare("INSERT INTO users (name,email,password,role) VALUES (?,?,?,'user')"); $stmt->execute([$name,$email,$hash]); header('Location: login.php?registered=1'); exit;}catch(PDOException $e){$error='Email already exists.';}} } ?>
<section class="auth-page"><form class="auth-card" method="POST"><h1>Create account</h1><?php if($error): ?><div class="error"><?= htmlspecialchars($error); ?></div><?php endif; ?><input name="name" required placeholder="Full name"><input name="email" type="email" required placeholder="Email"><input name="password" type="password" required placeholder="Password"><button class="btn">Register</button><p>Already have an account? <a href="login.php">Login</a></p></form></section><?php include 'footer.php'; ?>
